namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string DepartmentCode { get; set; } = string.Empty;
    public string CourseNumber { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private static readonly List<Department> Departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
        new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and fundamental forces." },
        new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
        new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." },
    ];

    private static readonly List<Course> Courses =
    [
        new() { Id = 1, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "101", Title = "Introduction to Programming", Description = "Foundational course covering programming concepts using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "MWF 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has published research on programming pedagogy.", IsFeatured = true },
        new() { Id = 2, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "201", Title = "Data Structures & Algorithms", Description = "In-depth study of arrays, linked lists, trees, graphs, sorting, and searching algorithms. Emphasis on complexity analysis.", Credits = 4, Schedule = "TTh 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm design and competitive programming. He coaches the university's ICPC team.", IsFeatured = true },
        new() { Id = 3, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "310", Title = "Database Systems", Description = "Relational database design, SQL, normalization, transactions, and an introduction to NoSQL databases.", Credits = 3, Schedule = "MWF 1:00–1:50 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked as a database architect at a Fortune 500 company before joining academia." },
        new() { Id = 4, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "450", Title = "Machine Learning", Description = "Supervised and unsupervised learning, neural networks, model evaluation, and practical applications using scikit-learn and TensorFlow.", Credits = 4, Schedule = "TTh 2:00–3:20 PM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has published research on programming pedagogy.", IsFeatured = true },
        new() { Id = 5, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "151", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "MWF 8:00–8:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator known for making calculus accessible to all students." },
        new() { Id = 6, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "250", Title = "Linear Algebra", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations.", Credits = 3, Schedule = "TTh 9:00–10:20 AM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson's research focuses on applied linear algebra in data science and quantum computing.", IsFeatured = true },
        new() { Id = 7, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "301", Title = "Probability & Statistics", Description = "Random variables, distributions, hypothesis testing, confidence intervals, and regression analysis.", Credits = 3, Schedule = "MWF 11:00–11:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator known for making calculus accessible to all students." },
        new() { Id = 8, DepartmentId = 3, DepartmentCode = "PHYS", CourseNumber = "101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based approach with weekly laboratory sessions.", Credits = 4, Schedule = "MWF 10:00–10:50 AM + Lab Thu 2:00–4:50 PM", InstructorName = "Dr. Alan Torres", InstructorBio = "Dr. Torres is an experimental physicist with a passion for hands-on learning." },
        new() { Id = 9, DepartmentId = 3, DepartmentCode = "PHYS", CourseNumber = "201", Title = "General Physics II", Description = "Electricity, magnetism, optics, and modern physics. Continuation of PHYS 101.", Credits = 4, Schedule = "MWF 10:00–10:50 AM + Lab Tue 2:00–4:50 PM", InstructorName = "Dr. Alan Torres", InstructorBio = "Dr. Torres is an experimental physicist with a passion for hands-on learning." },
        new() { Id = 10, DepartmentId = 4, DepartmentCode = "ENG", CourseNumber = "110", Title = "College Writing", Description = "Develops critical reading and academic writing skills. Emphasis on argument, evidence, and revision.", Credits = 3, Schedule = "MWF 9:00–9:50 AM", InstructorName = "Prof. Diana Hughes", InstructorBio = "Prof. Hughes is a published author and writing workshop facilitator with 20 years of teaching experience.", IsFeatured = true },
        new() { Id = 11, DepartmentId = 4, DepartmentCode = "ENG", CourseNumber = "250", Title = "American Literature", Description = "Survey of American literature from the colonial period to the present, exploring themes of identity and culture.", Credits = 3, Schedule = "TTh 1:00–2:20 PM", InstructorName = "Dr. Marcus Reed", InstructorBio = "Dr. Reed specializes in 20th-century American fiction and has authored two books on the Harlem Renaissance." },
        new() { Id = 12, DepartmentId = 5, DepartmentCode = "HIST", CourseNumber = "101", Title = "World History to 1500", Description = "Survey of world civilizations from antiquity through the late medieval period.", Credits = 3, Schedule = "TTh 11:00 AM–12:20 PM", InstructorName = "Dr. Fatima Al-Rashid", InstructorBio = "Dr. Al-Rashid is a specialist in medieval Mediterranean history and cross-cultural exchange." },
        new() { Id = 13, DepartmentId = 5, DepartmentCode = "HIST", CourseNumber = "225", Title = "Modern European History", Description = "Europe from the Enlightenment through the 20th century, covering revolutions, wars, and social change.", Credits = 3, Schedule = "MWF 2:00–2:50 PM", InstructorName = "Dr. Fatima Al-Rashid", InstructorBio = "Dr. Al-Rashid is a specialist in medieval Mediterranean history and cross-cultural exchange.", IsFeatured = true },
    ];

    public List<Department> GetDepartments() => Departments;

    public Department? GetDepartment(int id) => Departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = Courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseNumber.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.DepartmentCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => Courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => Courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In production, this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0
            && Courses.Any(c => c.Id == request.CourseId);
    }
}

