@page "/courses"
@inject CatalogService Catalog

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="/courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search by title, number, or instructor..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Course</th>
                <th>Title</th>
                <th>Credits</th>
                <th>Schedule</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.DepartmentCode @course.CourseNumber</td>
                    <td>@course.Title</td>
                    <td>@course.Credits</td>
                    <td>@course.Schedule</td>
                    <td>@course.InstructorName</td>
                    <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-secondary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> courses = [];
    private List<Department> departments = [];

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.GetCourses(Search, DepartmentId);
    }
}

@page "/enroll"
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit your enrollment request below. You will receive confirmation from the registrar's office.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Request Submitted!</strong> Your enrollment request for <em>@selectedCourseTitle</em> has been received.
        The registrar's office will contact you at your university email.
    </div>
    <a href="/courses" class="btn btn-primary">Browse More Courses</a>
}
else
{
    if (errorMessage is not null)
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    <form method="post" action="/enroll" class="col-md-6">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" class="form-control" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" required placeholder="e.g. S12345678" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="Model.CourseId" class="form-select" required>
                <option value="">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.DepartmentCode @course.CourseNumber – @course.Title</option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> courses = [];
    private bool submitted;
    private string? selectedCourseTitle;
    private string? errorMessage;

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    protected override void OnParametersSet()
    {
        if (HttpMethods.IsPost(HttpContextAccessor?.HttpContext?.Request.Method ?? "GET"))
        {
            if (Catalog.SubmitEnrollmentRequest(Model))
            {
                submitted = true;
                var course = Catalog.GetCourse(Model.CourseId);
                selectedCourseTitle = course is not null
                    ? $"{course.DepartmentCode} {course.CourseNumber} – {course.Title}"
                    : "Unknown Course";
            }
            else
            {
                errorMessage = "Please fill in all fields and select a valid course.";
            }
        }
    }

    [CascadingParameter] public HttpContext? HttpContextAccessor { get; set; }
}

